            .iter()
            .map(ToString::to_string)
            .collect::<Vec<_>>()
            .join(",");
        let url = format!(
            "{}/workspaces/{}/time_entries/{}",
            self.base_url, workspace_id, ids
        );
        self.patch::<Value, Value>(url, &patch).await
