        );

        let clients: HashMap<i64, crate::models::Client> = network_clients
            .unwrap_or_default()
            .into_iter()
            .map(|c| {
                (
                    c.id,
                    crate::models::Client {
                        id: c.id,
                        name: c.name,
                        workspace_id: c.wid,
                        archived: c.archived,
                    },
                )
            })
            .collect();

        let projects: HashMap<i64, Project> = network_projects
            .unwrap_or_default()
            .into_iter()
            .map(|p| {
                (
