use crate::api::client::ApiClient;
use crate::models::{ResultWithDefaultError, TimeEntry};
use crate::utilities;
use chrono::{Datelike, NaiveDate};
use std::collections::BTreeMap;

const BILLING_UNIT_SECONDS: i64 = 15 * 60;

pub struct BillWeeklyCommand;

fn billable_seconds(entry: &TimeEntry) -> Option<i64> {
    if !entry.billable || entry.stop.is_none() || entry.is_running() || entry.duration <= 0 {
        return None;
    }

    Some(
        ((entry.duration + BILLING_UNIT_SECONDS - 1) / BILLING_UNIT_SECONDS) * BILLING_UNIT_SECONDS,
    )
}

fn week_start(entry: &TimeEntry) -> NaiveDate {
    let date = entry.start.date_naive();
    date - chrono::Duration::days(date.weekday().num_days_from_monday() as i64)
}

fn aggregate(entries: &[TimeEntry]) -> BTreeMap<NaiveDate, i64> {
    let mut weeks = BTreeMap::new();
    for entry in entries {
        if let Some(seconds) = billable_seconds(entry) {
            *weeks.entry(week_start(entry)).or_insert(0) += seconds;
        }
    }
    weeks
}

impl BillWeeklyCommand {
    pub async fn execute(
        api_client: impl ApiClient,
        since: Option<String>,
        until: Option<String>,
    ) -> ResultWithDefaultError<()> {
        let (since, until) = utilities::normalize_time_entry_list_filters(since, until)?;
        let entries = api_client
            .get_time_entries_filtered_minimal(since, until)
            .await?;
        let weeks = aggregate(&entries);

        if weeks.is_empty() {
            println!("(no data)");
            return Ok(());
        }

        let mut total = 0;
        for (week, seconds) in weeks {
            println!("{}  {seconds}s", week.format("%Y-%m-%d"));
            total += seconds;
        }
        println!("Total  {total}s");
        Ok(())
    }
}

